namespace sv_a4e65c4d67484cca9c98c251fc7eec86.Models;

public class ApplicationData
{
    // Step 1 - Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2 - Experience
    public List<JobHistoryEntry> JobHistory { get; set; } = [];

    // Step 3 - References
    public List<ReferenceContact> References { get; set; } = [];

    // Track which steps are completed
    public HashSet<int> CompletedSteps { get; set; } = [];
}

public class JobHistoryEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
}

using System.Collections.Concurrent;
using sv_a4e65c4d67484cca9c98c251fc7eec86.Models;

namespace sv_a4e65c4d67484cca9c98c251fc7eec86.Services;

/// <summary>
/// Singleton service that stores wizard data keyed by session ID.
/// Each user gets their own entry via a session cookie, so data
/// is isolated even though the service is shared.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, ApplicationData> _store = new();

    public ApplicationData GetOrCreate(string sessionId)
    {
        return _store.GetOrAdd(sessionId, _ => new ApplicationData());
    }

    public void Remove(string sessionId)
    {
        _store.TryRemove(sessionId, out _);
    }
}

@inherits LayoutComponentBase
@inject NavigationManager Navigation
@inject Services.WizardStateStore StateStore
@inject IHttpContextAccessor HttpContextAccessor

<div class="container py-4">
    <header class="mb-4">
        <h2>Job Application</h2>
        <div class="d-flex gap-2 align-items-center mb-2">
            @for (int i = 0; i < Steps.Length; i++)
            {
                var step = Steps[i];
                var stepNumber = i + 1;
                var isCurrent = stepNumber == CurrentStep;
                var isCompleted = CompletedSteps.Contains(stepNumber);

                <a href="@step.Url"
                   class="btn btn-sm @(isCurrent ? "btn-primary" : isCompleted ? "btn-success" : "btn-outline-secondary")">
                    @stepNumber. @step.Label
                </a>
            }
        </div>
        <div class="progress" style="height: 8px;">
            <div class="progress-bar" style="width: @(CurrentStep * 25)%"></div>
        </div>
        <small class="text-muted">Step @CurrentStep of @Steps.Length</small>
    </header>

    <article>
        @Body
    </article>
</div>

@code {
    private static readonly (string Url, string Label)[] Steps =
    [
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience", "Experience"),
        ("/apply/references", "References"),
        ("/apply/review", "Review"),
    ];

    private int CurrentStep => GetCurrentStep();
    private HashSet<int> CompletedSteps => GetCompletedSteps();

    private int GetCurrentStep()
    {
        var path = Navigation.ToBaseRelativePath(Navigation.Uri).TrimStart('/');
        return path switch
        {
            "apply/personal-info" => 1,
            "apply/experience" => 2,
            "apply/references" => 3,
            "apply/review" => 4,
            _ => 1,
        };
    }

    private HashSet<int> GetCompletedSteps()
    {
        var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"];
        if (string.IsNullOrEmpty(sessionId))
            return [];

        var data = StateStore.GetOrCreate(sessionId);
        return data.CompletedSteps;
    }
}

