@page "/apply/personal-info"
@rendermode InteractiveServer
@layout Components.Layout.WizardLayout
@inject Services.WizardStateStore StateStore
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Navigation

<h3>Personal Information</h3>

<EditForm Model="model" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="model.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="model.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next &rarr;</button>
</EditForm>

@code {
    private PersonalInfoModel model = new();
    private string _sessionId = string.Empty;

    protected override void OnInitialized()
    {
        _sessionId = GetOrCreateSessionId();
        var data = StateStore.GetOrCreate(_sessionId);
        model.Name = data.Name;
        model.Email = data.Email;
    }

    private void Next()
    {
        var data = StateStore.GetOrCreate(_sessionId);
        data.Name = model.Name;
        data.Email = model.Email;
        data.CompletedSteps.Add(1);
        Navigation.NavigateTo("/apply/experience");
    }

    private string GetOrCreateSessionId()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        var sessionId = httpContext?.Request.Cookies["WizardSessionId"];
        if (string.IsNullOrEmpty(sessionId))
        {
            sessionId = Guid.NewGuid().ToString();
            httpContext?.Response.Cookies.Append("WizardSessionId", sessionId, new CookieOptions
            {
                HttpOnly = true,
                SameSite = SameSiteMode.Strict,
                Expires = DateTimeOffset.UtcNow.AddHours(2)
            });
        }
        return sessionId;
    }

    private class PersonalInfoModel
    {
        public string Name { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
    }
}

