        if (!string.IsNullOrEmpty(_sessionId))
        {
            var data = StateStore.GetOrCreate(_sessionId);
            entries = data.JobHistory.Select(j => new Models.JobHistoryEntry
            {
                Company = j.Company,
                Title = j.Title,
                Years = j.Years
            }).ToList();
        }
