toolArgs.file_text:
@page "/apply/review"
@rendermode InteractiveServer
@layout Components.Layout.WizardLayout
@inject Services.WizardStateStore StateStore
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Navigation

<h3>Review Your Application</h3>

@if (data is not null)
{
    <div class="card mb-3 p-3">
        <h5>Personal Information</h5>
        <p><strong>Name:</strong> @data.Name</p>
        <p><strong>Email:</strong> @data.Email</p>
    </div>

    <div class="card mb-3 p-3">
        <h5>Work Experience</h5>
        @if (data.JobHistory.Count == 0)
        {
            <p class="text-muted">No entries added.</p>
        }
        else
        {
            @foreach (var job in data.JobHistory)
            {
                <div class="mb-2">
                    <strong>@job.Title</strong> at @job.Company (@job.Years)
                </div>
            }
        }
    </div>

    <div class="card mb-3 p-3">
        <h5>References</h5>
        @if (data.References.Count == 0)
        {
            <p class="text-muted">No references added.</p>
        }
        else
        {
            @foreach (var r in data.References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> — @r.Email (@r.Relationship)
                </div>
            }
        }
    </div>

    <div class="d-flex gap-2">
        <a href="/apply/references" class="btn btn-outline-secondary">&larr; Back</a>
        <button type="button" class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>
}

@code {
    private Models.ApplicationData? data;

    protected override void OnInitialized()
    {
        var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"];
        if (!string.IsNullOrEmpty(sessionId))
        {
            data = StateStore.GetOrCreate(sessionId);
        }
    }

    private void Submit()
    {
        // In a real app, persist to database here and clear the session
        Navigation.NavigateTo("/");
    }
}

